import { useState, useEffect, useCallback } from "react";
import axios from "axios";

import Navbar      from "./components/Navbar";
import Hero        from "./components/Hero";
import FormPanel   from "./components/FormPanel";
import TablePanel  from "./components/TablePanel";
import DeleteModal from "./components/DeleteModal";
import Toast       from "./components/Toast";
import Footer      from "./components/Footer";

import { EMPTY_FORM } from "./constants";

const API_URL = "http://localhost:8080/agendamento";

export default function App() {
  const [appointments, setAppointments] = useState([]);
  const [form, setForm] = useState(EMPTY_FORM || {}); // Trava caso EMPTY_FORM seja undefined
  const [editingId, setEditingId] = useState(null);
  const [activeNav, setActiveNav] = useState("Início");
  const [deleteTarget, setDeleteTarget] = useState(null);
  const [toast, setToast] = useState(null);

  const showToast = (msg, type = "success") => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  };

  const fetchAppointments = useCallback(async () => {
    try {
      const response = await axios.get(API_URL);
      // Adicionamos verificações (.split) para não quebrar se a data vier errada
      const formattedData = (response.data || []).map(item => {
        const dataPartes = item.dataHora ? item.dataHora.split('T') : ["", ""];
        return {
          id: item.id,
          name: item.clienteNome || "Sem nome",
          service: item.servico || "Não informado",
          date: dataPartes[0] || "",
          time: dataPartes[1] ? dataPartes[1].substring(0, 5) : "",
          status: "confirmado"
        };
      });
      setAppointments(formattedData);
    } catch (error) {
      console.error("Erro na API:", error);
      showToast("Erro ao carregar agendamentos.", "error");
    }
  }, []);

  useEffect(() => {
    fetchAppointments();
  }, [fetchAppointments]);

  // Se nada renderizar, esse log vai nos avisar no F12
  console.log("App renderizando. Agendamentos:", appointments);

  return (
    <div>
      {/* Usamos renderização condicional simples para testar */}
      {NAV_LINKS && <Navbar active={activeNav} setActive={setActiveNav} />}
      <Hero />
      <div className="pb-main">
        <FormPanel
          form={form}
          setForm={setForm}
          editing={editingId !== null}
          onSubmit={handleSubmit}
          onCancel={() => { setForm(EMPTY_FORM); setEditingId(null); }}
        />
        {/* Passamos uma lista vazia por padrão caso appointments falhe */}
        <TablePanel
          appointments={appointments || []}
          onEdit={handleEdit}
          onDeleteRequest={setDeleteTarget}
        />
      </div>
      <Footer />
      <DeleteModal
        target={deleteTarget}
        onConfirm={handleDelete}
        onCancel={() => setDeleteTarget(null)}
      />
      <Toast toast={toast} />
    </div>
  );

  // Handlers omitidos para brevidade (mantenha os seus, estão corretos)
}
